#!/usr/bin/env bash
set -euo pipefail

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
SRC_DIR="$ROOT_DIR/src"
OUT_FILE="$SRC_DIR/WCPLMessageHook.xm"
TMP_FILE="$(mktemp)"

cleanup() {
  rm -f "$TMP_FILE"
}
trap cleanup EXIT

cat > "$TMP_FILE" <<'HEADER'
#import "WCPLMessageHookCommon.h"

// AUTO-GENERATED FILE.
// Source modules:
// - WCPLMessageHookCommon.xm
// - WCPLMessageSearchCore.xm
// - WCPLMessageSearchHook.xm
// - WCPLMessageLongPressMenuHook.xm
// - WCPLMessageLocalReplaceHook.xm
// - WCPLVoiceForwardCore.xm
// - WCPLVoiceForwardHook.xm
// - WCPLClownFeatureHook.xm
//
// WCPLMessageHook.xm is a generated aggregation artifact.
// Do not edit this file manually. Edit module files and rerun:
//   scripts/generate_wcpl_message_hook.sh
HEADER

MODULE_FILES=(
  "WCPLMessageHookCommon.xm"
  "WCPLMessageSearchCore.xm"
  "WCPLMessageSearchHook.xm"
  "WCPLMessageLongPressMenuHook.xm"
  "WCPLMessageLocalReplaceHook.xm"
  "WCPLVoiceForwardCore.xm"
  "WCPLVoiceForwardHook.xm"
  "WCPLClownFeatureHook.xm"
)

for module in "${MODULE_FILES[@]}"; do
  printf '\n// ===== %s =====\n\n' "$module" >> "$TMP_FILE"
  cat "$SRC_DIR/$module" >> "$TMP_FILE"
  printf '\n' >> "$TMP_FILE"
done

if cmp -s "$TMP_FILE" "$OUT_FILE" 2>/dev/null; then
  exit 0
fi

mv "$TMP_FILE" "$OUT_FILE"
echo "[wcpl] regenerated src/WCPLMessageHook.xm"
